INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('18-patient-community',2,18,'PATIENT COMMUNITY','Cong dong benh nhan',18,'draft','2026-06-20T14:59:01Z','2026-06-20T14:59:01Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('150ba858-490f-417c-89e9-91780415d84e','18-patient-community',NULL,2,'18.1 Sự dịch chuyển tư duy: Vây thành và Lập Cộng Đồng','181-su-dich-chuyen-tu-duy-vay-thanh-va-lap-cong-ong',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ee0eb666-9f88-4b3d-826c-3f6fa50033f8','150ba858-490f-417c-89e9-91780415d84e',0,'text','Kiến Tạo Hệ Sinh Thái Khách Hàng Thân Thiết Và Tối Ưu Hóa Giá Trị Vòng Đời Hậu Điều Trị',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22bcf13a-c9b3-4cfb-aed0-d9e0b95e1048','150ba858-490f-417c-89e9-91780415d84e',1,'text','Chúng ta vừa khép lại** Referral Ecosystem** với một bộ quy trình hoàn chỉnh để số hóa lòng biết ơn, đóng gói các ca lâm sàng thành vũ khí hạng nặng và khơi thông dòng khách truyền miệng chất lượng cao với chi phí CAC (Chi phí thu mua khách hàng) tiệm cận bằng 0. Hệ thống này đã giải quyết xuất sắc bài toán: *Làm sao để dùng niềm tin của bệnh nhân cũ để mở cánh cửa căn phòng tâm lý của khách hàng mới.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f29e8786-5e0f-4cc7-a20a-514904764cf4','150ba858-490f-417c-89e9-91780415d84e',2,'text','Tuy nhiên, nếu nhìn sâu vào bản chất vận hành của toàn bộ trục **Growth Engine**, một lời giới thiệu, một bài review 5 sao trên Google Maps hay một thước phim Short Testimonial suy cho cùng vẫn là những hành động mang tính **khoảnh khắc**. Chúng được kích hoạt dựa trên những mốc cảm xúc đỉnh cao đột xuất (*Wow Peak*) của bệnh nhân tại một thời điểm tuyến tính trong quá trình điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('22881aca-aa79-4ae0-a82c-e31bae4381f4','150ba858-490f-417c-89e9-91780415d84e',3,'text','Một câu hỏi hóc búa mang tính sống còn đối với nhà quản trị nha khoa thực chiến được đặt ra:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('57fcff84-30b6-402c-b0fb-8d20f4ee6c36','150ba858-490f-417c-89e9-91780415d84e',4,'text','**Sau khi bệnh nhân cũ đã giới thiệu xong người nhà, sau khi họ đã quét mã QR để lại đánh giá 5 sao rực rỡ, mối liên kết giữa họ và phòng khám sẽ đi về đâu trong 1 năm, 3 năm, hay 5 năm kế tiếp?**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16cd0f17-937b-48c9-99e9-9f9fee04913e','150ba858-490f-417c-89e9-91780415d84e',5,'text','Nếu phòng khám của bạn chỉ im lặng, lưu hồ sơ của họ vào kho dữ liệu CRM và chỉ chủ động nhắn tin lại khi họ đến hạn cạo vôi răng, bạn đang phạm phải một sai lầm chí mạng: **Đóng băng tài sản hệ sinh thái**. Cảm xúc dù có mãnh liệt đến đâu cũng sẽ nguội lạnh theo thời gian. Nếu không có một "hồ chứa" đủ lớn để liên tục nuôi dưỡng, dòng khách Referral dù có mạnh mẽ đến mấy cũng sẽ đến ngày chạm trần và phân rã.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('709a7cb0-617b-403b-99f3-d363b8f9cc91','150ba858-490f-417c-89e9-91780415d84e',6,'text','Đó là lý do vì sao hệ điều hành **Dental Empire OS** bắt buộc phải kích hoạt phân hệ tối thượng tiếp theo: **Chương 18 - Patient Community**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d89539c1-9a8c-4e3a-aa38-80cd70d2891b','150ba858-490f-417c-89e9-91780415d84e',7,'text','Nếu **Chương 17 (Referral System)** dạy bạn kỹ thuật "phóng lao" - tức là săn đón niềm tin để kéo dòng khách mới về ghế nha, thì **Chương 18 (Patient Community)** sẽ dạy bạn nghệ thuật "vây thành" thiết lập một hệ sinh thái khép kín hậu điều trị để tối ưu hóa triệt để Giá trị vòng đời khách hàng (Lifetime Value - LTV).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c713d9e-7922-4270-9974-d59ecebaa65f','150ba858-490f-417c-89e9-91780415d84e',8,'text','Chúng ta sẽ chính thức nâng cấp vị thế của bệnh nhân:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c6fd8ec2-4f3f-47ac-b42e-b8d9c5b022f0','150ba858-490f-417c-89e9-91780415d84e',9,'text','- Từ một **"Giao dịch đơn lẻ"** thành một **"Tài sản dài hạn"**.- Từ một **"Người mua dịch vụ nha khoa"** thành một **"Thành viên của cộng đồng"**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1ad5d937-f815-4f38-b1be-2c5074069be9','150ba858-490f-417c-89e9-91780415d84e',10,'text','Bước sang Chương 18, toàn bộ các lát cắt về công nghệ CRM, kỹ thuật phân tầng thẻ hội viên, chiến lược giáo dục y khoa thường thức và nghệ thuật cá nhân hóa đặc quyền sẽ được hòa làm một, vận hành nhịp nhàng dưới hai bộ công thức thép kiểm soát tỷ lệ giữ chân khách hàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d076536-82ab-4cef-967a-7daf825266dc','150ba858-490f-417c-89e9-91780415d84e',11,'image',NULL,'book/18-patient-community/681a145f-c2d6-4c2a-b0b5-bf37b37b9a61-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f38668c6-cc57-4e2a-9b9b-74c4dd3f8593','150ba858-490f-417c-89e9-91780415d84e',12,'text','Và',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f981383f-e4da-48bb-9ece-97196cd5e835','150ba858-490f-417c-89e9-91780415d84e',13,'image',NULL,'book/18-patient-community/eada6eb6-88af-4801-89e8-bb7207a77dad-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0e426789-e4fd-4320-80f4-0ec06ee72821','18-patient-community',NULL,2,'18.2 Diễn biến tâm lý bệnh nhân hậu điều trị','182-dien-bien-tam-ly-benh-nhan-hau-ieu-tri',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bf947f9d-84c2-4a43-abd3-03f19a487a0c','0e426789-e4fd-4320-80f4-0ec06ee72821',14,'text','**Cuộc chiến chống lại sự lãng quên và nhu cầu được thuộc về**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('72588ca2-22f6-4756-8f38-f51582b8740a','0e426789-e4fd-4320-80f4-0ec06ee72821',15,'text','Trong thế giới của nha khoa kỹ trị, có một sự thật phũ phàng mà các Bác sĩ và Nhà quản lý phải chấp nhận: **Khi nỗi đau thể xác biến mất, động lực y khoa của bệnh nhân cũng lập tức giảm về mốc số 0.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('11e854e5-47f7-476e-864d-48d0f1f02362','0e426789-e4fd-4320-80f4-0ec06ee72821',16,'text','Ngay khi bước xuống khỏi ghế răng với một hàm răng không còn ê buốt, một nụ cười răng sứ bừng sáng hay một cung niềng ổn định, tâm lý bệnh nhân sẽ dịch chuyển từ trạng thái "khẩn cấp, lo âu" sang trạng thái "an tâm nhưng thụ động". Nếu hệ thống của bạn dừng lại ở đây, sự lãng quên tự nhiên sẽ bắt đầu vận hành. Bệnh nhân sẽ nhanh chóng bị cuốn vào guồng quay cuộc sống và dần mất đi sợi dây liên kết với phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3699f01f-3ef8-4df0-9f13-2fa51ad5b338','0e426789-e4fd-4320-80f4-0ec06ee72821',17,'text','Để kiểm soát và tái định hướng hành vi của họ, hệ điều hành **Dental Empire OS** không nhìn nhận hậu điều trị như một khoảng lặng. Trái lại, chúng tôi bóc tách 4 chiều kích tâm lý cốt lõi của bệnh nhân trong giai đoạn này để thiết kế các điểm chạm kỹ thuật chuẩn xác:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('aade5ea6-045f-45af-8081-74984962a8e3','18-patient-community','0e426789-e4fd-4320-80f4-0ec06ee72821',3,'Nhu cầu xác thực sự tử tế:','nhu-cau-xac-thuc-su-tu-te',2,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('487dbf37-31f8-4718-b51b-31251ed749c6','aade5ea6-045f-45af-8081-74984962a8e3',18,'text','**Đánh giá phòng khám qua bộ lọc Chăm sóc chủ động**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('89406917-be3d-426f-a7d9-f1ba1f11cde9','aade5ea6-045f-45af-8081-74984962a8e3',19,'text','Khi một ca điều trị lớn khép lại và dòng tiền đã được thanh toán, bộ lọc hoài nghi trong tâm trí bệnh nhân sẽ tự động kích hoạt. Họ bắt đầu ngầm quan sát và đặt câu hỏi: *"Phòng khám này đối xử tốt với mình là vì họ muốn chốt doanh số, hay vì họ thực sự chịu trách nhiệm và quan tâm đến sức khỏe trọn đời của mình?"*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('efab7421-7049-4ca7-8da3-327e3af1c97c','aade5ea6-045f-45af-8081-74984962a8e3',20,'text','- **Cơ chế tâm lý:** Nếu phòng khám chỉ liên hệ khi muốn bán thêm dịch vụ, mối quan hệ sẽ gãy đổ vì bản chất thương mại lộ liễu. Nhưng nếu họ nhận được những tin nhắn dặn dò cá nhân hóa, những cuộc gọi hỏi thăm đúng mốc thời gian một cách đều đặn và tinh tế, não bộ của họ sẽ tự động thiết lập một phản xạ: **Nơi này coi mình là một con người, một thành viên VIP chứ không phải một mã doanh thu.**- **Chỉ số định hình:** Sự tương tác đều đặn chính là chất xúc tác biến lòng biết ơn nhất thời thành niềm tin vĩnh cửu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('70dec968-0374-4e7d-ae14-0128a8f8074a','18-patient-community','0e426789-e4fd-4320-80f4-0ec06ee72821',3,'Nhu cầu làm chủ tri thức:','nhu-cau-lam-chu-tri-thuc',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('18c39893-04f9-41e5-bdb9-6d20aa453fdd','70dec968-0374-4e7d-ae14-0128a8f8074a',21,'text','**Khát vọng cập nhật kiến thức để bảo vệ "thành quả"**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('23e09fc6-dfba-4838-8f4e-23003ff23b8b','70dec968-0374-4e7d-ae14-0128a8f8074a',22,'text','Sau khi đầu tư một khoản tài chính và thời gian không nhỏ cho răng miệng, bệnh nhân có xu hướng chuyển sang trạng thái "phòng thủ và bảo tồn". Họ sợ những chiếc răng sứ đắt tiền bị mẻ, sợ trụ implant bị đào thải, sợ răng niềng bị chạy lại vị trí cũ. Tuy nhiên, họ lại thiếu kiến thức y khoa thường thức để tự chăm sóc đúng cách tại nhà.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4371ac4b-7ee6-4bf6-866a-c9b0f4d62354','70dec968-0374-4e7d-ae14-0128a8f8074a',23,'text','- **Cơ chế tâm lý:** Bệnh nhân luôn có nhu cầu tìm kiếm và cập nhật kiến thức về sức khỏe răng miệng, nhưng họ lười đọc những tài liệu y khoa khô khan, giáo điều. Họ cần một nguồn thông tin có thẩm quyền (**Authority**), ngắn gọn, dễ hiểu và mang tính thực chiến cao. Khi phòng khám chủ động cung cấp nguồn tri thức này, bạn không chỉ giúp họ bảo vệ thành quả lâm sàng của *Clinic System*, mà còn định vị bản thân là người dẫn đường đáng tin cậy trong tâm trí họ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('133f59d5-f677-4997-972f-49b7a0d3d908','18-patient-community','0e426789-e4fd-4320-80f4-0ec06ee72821',3,'Kỳ vọng vào "Người trợ lý thông minh":','ky-vong-vao-nguoi-tro-ly-thong-minh',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc52be92-d38d-44ba-94a4-5ce2006a6276','133f59d5-f677-4997-972f-49b7a0d3d908',24,'text','**Nhắc lịch tái khám đúng chu kỳ sinh học**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13d90e09-38bd-4b3b-981e-9e2abfcb6475','133f59d5-f677-4997-972f-49b7a0d3d908',25,'text','Bệnh nhân không cố ý trốn tránh lịch tái khám, họ chỉ đơn giản là quên. Họ không thể tự nhớ được khi nào thì đến hạn cạo vôi răng định kỳ 6 tháng, khi nào cần quay lại kiểm tra khớp cắn hay kiểm tra độ khít sát của phục hình sứ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0882cdb-539e-442e-ae82-da5a6952d1f1','133f59d5-f677-4997-972f-49b7a0d3d908',26,'text','- **Cơ chế tâm lý:** Bệnh nhân ghét cảm giác bị làm phiền bởi những cuộc gọi chèo kéo vô duyên, nhưng họ lại cực kỳ thỏa mãn nếu phòng khám đóng vai trò như một "trợ lý sức khỏe" công nghệ cao. Một lời nhắc lịch xuất hiện **đúng lúc, đúng chu kỳ sinh học** giải phóng họ khỏi việc phải ghi nhớ. Điều này tạo ra sự chuyên nghiệp tuyệt đối, khiến họ cảm thấy mình đang được bao bọc trong một hệ thống vận hành thông minh và tận tụy.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71697421-534d-4e6d-b20c-20fbf098bfb9','18-patient-community','0e426789-e4fd-4320-80f4-0ec06ee72821',3,'Nhu cầu thuộc về một "Vùng an toàn" (The Trusted Sanctuary)','nhu-cau-thuoc-ve-mot-vung-an-toan-the-trusted-sanctuary',5,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('02b7b7b9-fea6-4e12-9ead-95226ed05f73','71697421-534d-4e6d-b20c-20fbf098bfb9',27,'text','Xu hướng tâm lý sâu thẳm của con người là luôn tìm kiếm một môi trường, một cộng đồng đáng tin cậy để gửi gắm niềm tin lâu dài. Trong bối cảnh thị trường nha khoa thật giả lẫn lộn, việc tìm thấy một phòng khám RHM tử tế mang lại cho họ một cảm giác an toàn rất lớn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ec52d25-3f8b-4871-8ea2-eecce918cd86','71697421-534d-4e6d-b20c-20fbf098bfb9',28,'text','- **Cơ chế tâm lý:** Khi được tham gia vào một hệ sinh thái chăm sóc toàn diện, được lắng nghe ý kiến, được tham gia vào các hoạt động hội viên và nhìn thấy những người khác cũng có cùng trải nghiệm hạnh phúc giống mình, bệnh nhân sẽ nảy sinh **Tâm lý bộ tộc (Tribe Psychology)**. Họ không còn coi mình là người ngoài, họ tự hào vì là một phần của cộng đồng **Thích Làm Răng**. Chính nhu cầu thuộc về này là mỏ neo tối thượng giữ chân họ ở lại với phòng khám trọn đời.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3c119ec1-bc60-4bc0-abc2-e54cb4e29e2b','71697421-534d-4e6d-b20c-20fbf098bfb9',29,'text','**Mô hình hóa Chỉ số gắn kết cảm xúc hậu điều trị (****E_{community}****):**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b25f66ba-7c43-4891-9634-4a265d018f2e','71697421-534d-4e6d-b20c-20fbf098bfb9',30,'image',NULL,'book/18-patient-community/d42d95a0-7828-4097-a98d-604350e8c4b0-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bde0e2af-8b05-4ea7-9447-5ab4bd3fed62','71697421-534d-4e6d-b20c-20fbf098bfb9',31,'text','Hiểu rõ trục dọc tâm lý này, nhà quản trị không thể chỉ dựa vào thái độ phục vụ nhất thời, mà phải dùng hệ thống CRM để lập trình sẵn các đường ống nội dung, kịch bản recall nhằm đáp ứng chính xác từng nhu cầu ẩn giấu của bệnh nhân, biến họ thành một tài sản tăng trưởng vĩnh cửu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93','18-patient-community',NULL,2,'18.3 Mục tiêu chiến lược của Patient Community:','183-muc-tieu-chien-luoc-cua-patient-community',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('046be367-120b-493a-a3c5-8382153ef449','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',32,'text','**Tối ưu hóa động cơ doanh thu hữu cơ và đa dạng hóa mô hình giá trị**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4870ea9f-f2cc-4e98-83bc-0ffaf56f24e8','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',33,'text','Trong hệ điều hành **Dental Empire OS**, tầng **Patient Community** không được xây dựng để làm từ thiện hay chỉ để tổ chức các hoạt động bề nổi cho vui vẻ. Đây là một phân hệ kiến trúc tài chính cốt lõi, có nhiệm vụ chuyển đổi toàn bộ giá trị cảm xúc của bệnh nhân thành các chỉ số tăng trưởng kinh tế hữu cơ cho phòng khám RHM.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('98fd0623-1f5a-48cf-a7b2-12125fd18df4','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',34,'text','Mục tiêu tối thượng của tầng này là phá vỡ giới hạn doanh thu trần của các dịch vụ lâm sàng truyền thống, đồng thời tối ưu hóa triệt để chỉ số **Giá trị vòng đời bệnh nhân (Patient Lifetime Value - LTV)** thông qua một mô hình toán học quản trị:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c2cce0d-35c2-4a9c-8bab-7b93a84c35a5','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',35,'text','LTV_{\\text{Total}} = \\sum (Doanh\\ thu_{\\text{Lâm\\ sàng}}) + \\sum (Doanh\\ thu_{\\text{Hệ\\ sinh\\ thái}}) + Giá\\ trị_{\\text{Lan\\ tỏa\\ (Referral)}}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('38781abc-9ea5-4ffc-9abf-f947013086b5','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',36,'image',NULL,'book/18-patient-community/c4872048-de06-4484-8b94-0f0c19f28467-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7fcf696e-9b82-42ac-86df-5924dcf7adc7','18-patient-community','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',3,'Bốn mục tiêu tăng trưởng nền móng (The core retention engine)','bon-muc-tieu-tang-truong-nen-mong-the-core-retention-engine',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('609e30b5-cb1e-44b1-863d-3831e676359b','7fcf696e-9b82-42ac-86df-5924dcf7adc7',37,'text','Bằng việc vận hành một cộng đồng bệnh nhân gắn kết, phòng khám sẽ trực tiếp tác động vào 4 chỉ số sinh tử của bài toán tăng trưởng dài hạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('239adb3b-6937-404d-8f6d-96f875257cd0','7fcf696e-9b82-42ac-86df-5924dcf7adc7',38,'text','- **Tăng tỷ lệ giữ chân (Maximize Retention Rate):** Thiết lập một "hàng rào cảm xúc" và quyền lợi đặc quyền khiến bệnh nhân không có bất kỳ lý do gì để chuyển sang phòng khám đối thủ. Khi chi phí chuyển đổi (Switching Cost) về mặt tâm lý và quyền lợi quá cao, tỷ lệ rời bỏ hệ thống (Churn Rate) của bệnh nhân sẽ tự động giảm về mức tối thiểu.- **Tăng tỷ lệ tái khám chủ động (Boost Recall Rate):** Giữ cho công suất sử dụng ghế nha luôn đạt mức tối ưu vào các ngày trong tuần. Nhờ các kịch bản nhắc lịch và chăm sóc định kỳ được lập trình sẵn, phòng khám luôn có một dòng khách quay lại đều đặn để cạo vôi răng, tầm soát túi nha chu hoặc bảo dưỡng phục hình mà không tốn thêm một đồng chi phí quảng cáo nào.- **Tăng sản lượng lan tỏa tự nhiên (Amplified Referrals):** Khi bệnh nhân thuộc về một cộng đồng mà họ tự hào, hành vi giới thiệu người thân sẽ diễn ra như một phản xạ tự nhiên. Cộng đồng chính là môi trường nuôi dưỡng, giữ cho ngọn lửa lòng biết ơn của họ luôn ấm nóng, biến họ thành những "chiến binh truyền thông" hoạt động bền bỉ cho phòng khám.- **Kéo giãn Giá trị vòng đời bệnh nhân (Lifetime Value Extension):** Thay vì chỉ khai thác được giá trị của bệnh nhân trong vòng vài tuần hay vài tháng điều trị lâm sàng, hệ thống sẽ kéo dài dòng tiền từ một hồ sơ khách hàng lên đến 5 năm, 10 năm, hoặc thậm chí là trọn đời thông qua các phân hệ dịch vụ gia tăng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8175ec29-edb4-4063-a789-08ae6d1b13c4','18-patient-community','a1a4ebd9-2a32-4b23-b0f6-ad6e1e973d93',3,'Đa dạng hóa nguồn thu hậu điều trị (The ecosystem revenue streams)','a-dang-hoa-nguon-thu-hau-ieu-tri-the-ecosystem-revenue-streams',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('05c3c050-b19e-4ecc-b668-3dd05be24e7f','8175ec29-edb4-4063-a789-08ae6d1b13c4',39,'text','Vượt ra khỏi ranh giới của những chiếc ghế nha và tiếng máy khoan, **Patient Community** mở ra một chương mới cho mô hình kinh doanh phòng khám RHM: **Nền kinh tế hệ sinh thái nha khoa (Dental Ecosystem Economy)**. Phòng khám sẽ chủ động tạo ra những dòng doanh thu phụ nhưng có biên lợi nhuận thuần cực cao từ các cấu phần:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e6af63cb-df5a-4256-98d3-bc626456844c','18-patient-community','8175ec29-edb4-4063-a789-08ae6d1b13c4',5,'A. Doanh thu từ Chương trình Hội viên (Membership Subscriptions)','a-doanh-thu-tu-chuong-trinh-hoi-vien-membership-subscriptions',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7956d623-58d3-4f92-8144-70048d45e487','e6af63cb-df5a-4256-98d3-bc626456844c',40,'text','- **Mô hình vận hành:** Thiết lập các gói thẻ hội viên trả trước theo năm dành cho cá nhân hoặc hộ gia đình (Family Healthcare Pass).- **Giá trị mang lại:** Bệnh nhân đóng một khoản phí cố định hằng năm để đổi lấy các đặc quyền: miễn phí cạo vôi răng trọn năm, ưu tiên đặt lịch Bác sĩ trưởng ca, giảm giá độc quyền cho các dịch vụ phát sinh và miễn phí tầm soát công nghệ cao. Gói hội viên này giúp phòng khám thu được dòng tiền mặt trước (Upfront Cashflow) và trói chân khách hàng dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('93bd9ba1-ec9b-4a6a-a13b-2657f254a9cb','18-patient-community','8175ec29-edb4-4063-a789-08ae6d1b13c4',5,'B. Doanh thu từ Sản phẩm chăm sóc tại nhà (Homecare Product Retail)','b-doanh-thu-tu-san-pham-cham-soc-tai-nha-homecare-product-retail',10,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cc6c05c1-c621-4f4c-aa6f-948a32d8a46d','93bd9ba1-ec9b-4a6a-a13b-2657f254a9cb',41,'text','- **Mô hình vận hành:** Đóng gói và phân phối các bộ giải pháp chăm sóc răng miệng chuyên sâu phù hợp với từng tệp bệnh nhân sau điều trị (Ví dụ: Set quà cho răng sứ, bộ vệ sinh chuyên dụng cho người niềng răng, máy tăm nước công nghệ sóng siêu âm độc quyền của phòng khám).- **Giá trị mang lại:** Bác sĩ kê đơn sản phẩm ngay tại ghế nha như một phần bắt buộc của phác đồ bảo tồn kết quả. Bệnh nhân yên tâm vì mua được sản phẩm chính hãng, có sự bảo chứng chuyên môn từ Bác sĩ, còn phòng khám kích hoạt được một nguồn doanh thu bán lẻ (Retail Revenue) lặp lại đều đặn hằng tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9bab5623-635b-4d11-9d55-f20b514cadf2','18-patient-community','8175ec29-edb4-4063-a789-08ae6d1b13c4',5,'C. Doanh thu từ Workshops và Hoạt động giáo dục định kỳ (Educational Events)','c-doanh-thu-tu-workshops-va-hoat-ong-giao-duc-inh-ky-educational-events',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7f5b8c3a-c31d-4396-aa2d-d23a0bbb6efe','9bab5623-635b-4d11-9d55-f20b514cadf2',42,'text','- **Mô hình vận hành:** Tổ chức các buổi hội thảo, chia sẻ tri thức theo chuyên đề y khoa thường thức tại phòng khám hoặc qua Zoom (Ví dụ: *"Workshops: Nghệ thuật chăm sóc răng sữa cho con — Hành trang cho mẹ bỉm hiện đại"*, hoặc *"Chuyên đề: Kiểm soát lão hóa tầng mặt dưới cho phụ nữ sau 35 tuổi"*).- **Giá trị mang lại:** Phòng khám có thể thu một khoản phí ghi danh nhỏ để lọc tệp chất lượng, hoặc mở cửa miễn phí như một cái phễu thu hút lead cực mạnh. Đây là nơi chúng ta chuyển hóa những người tham dự từ trạng thái tò mò trở thành bệnh nhân chính thức của phòng khám thông qua sức mạnh giáo dục tri thức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c518f593-303e-45ee-bc09-2a39ea3b3134','9bab5623-635b-4d11-9d55-f20b514cadf2',43,'text','**Góc nhìn quản trị tầng cao:** Một phòng khám nha khoa thông thường sẽ sụp đổ nếu dịch bệnh hoặc thị trường biến động khiến lượng khách mới sụt giảm. Nhưng một phòng khám vận hành theo tiêu chuẩn **Dental Empire OS** với một **Patient Community** vững chắc sẽ luôn sống khỏe, bởi vì nguồn thu từ Membership, bán lẻ sản phẩm Homecare và dòng khách quay lại tái khám đã thừa sức bao phủ toàn bộ chi phí vận hành cố định của phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('625501e2-fd8a-4862-957e-d1ed06a7feb7','18-patient-community',NULL,2,'18.4 Kênh chính của Patient Community: đúng ngữ cảnh, trúng đối tượng','184-kenh-chinh-cua-patient-community-ung-ngu-canh-trung-oi-tuong',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1bc25a3a-89ca-4ccf-b330-bc84d56e67ab','625501e2-fd8a-4862-957e-d1ed06a7feb7',44,'text','Một sai lầm phổ biến khi xây dựng cộng đồng nha khoa là biến tất cả các kênh liên lạc thành những "họng súng" bom tin nhắn quảng cáo khuyến mãi. Bệnh nhân sẽ lập tức chặn số, hủy quan tâm hoặc rời nhóm nếu họ cảm thấy bị làm phiền.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('60f2caff-a151-4d31-8d14-67e37e1f87d5','625501e2-fd8a-4862-957e-d1ed06a7feb7',45,'text','Trong hệ điều hành **Dental Empire OS**, mạng lưới truyền thông đa kênh được thiết kế dựa trên nguyên tắc **Đúng ngữ cảnh (Contextual Interaction)**. Phòng khám RHM cần phân phối thông điệp qua các kênh tương ứng với từng tệp bệnh nhân chuyên biệt để giữ sợi dây liên lạc tự nhiên nhất',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cdbcb4a9-2b75-45e8-a597-d92668ffb060','625501e2-fd8a-4862-957e-d1ed06a7feb7',46,'image',NULL,'book/18-patient-community/5a5d3a7e-453a-4fba-abc5-8f477fa67b46-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('71b71408-f665-4116-b404-590c30d886d3','18-patient-community','625501e2-fd8a-4862-957e-d1ed06a7feb7',3,'Chi tiết vai trò của các kênh trong hệ thống recall','chi-tiet-vai-tro-cua-cac-kenh-trong-he-thong-recall',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('af42433a-f750-47bf-b086-ca61e9359487','71b71408-f665-4116-b404-590c30d886d3',47,'text','- **Zalo OA (Official Account):** Trục xương sống để tự động hóa thông báo. Sử dụng tính năng ZNS (Zalo Notification Service) để tự động bắn tin nhắn xác nhận lịch hẹn, chúc mừng sinh nhật, và phân phối danh sách Broadcast giáo dục theo tag phân khúc.- **Zalo Cá nhân (Tài khoản CSKH/Bác sĩ):** Kênh tương ứng với các ca điều trị can thiệp sâu, cần độ bảo mật và tính riêng tư cao. Tạo cảm giác chăm sóc đặc quyền 1-1, giúp bệnh nhân dễ dàng chụp ảnh tình trạng nướu/răng gửi Bác sĩ kiểm tra từ xa.- **Hệ thống Recall tự động (CRM-Driven):** Động cơ ngầm tự động tính toán chu kỳ 6 tháng của từng hồ sơ để kích hoạt lệnh nhắc lịch cạo vôi răng, tầm soát định kỳ, giữ cho công suất ghế nha của hệ thống luôn được lấp đầy một cách chủ động.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('ef3b12ad-2e22-4294-9b4b-349ece77265d','18-patient-community','625501e2-fd8a-4862-957e-d1ed06a7feb7',3,'Hình thức triển khai và chiến lược xây dựng tiểu cộng đồng chuyên biệt (Micro-Communities)','hinh-thuc-trien-khai-va-chien-luoc-xay-dung-tieu-cong-ong-chuyen-biet-micro-comm',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff3e0b58-0d46-4166-b4ae-7b6402e247fd','ef3b12ad-2e22-4294-9b4b-349ece77265d',48,'text','Để tối ưu hóa tỷ lệ tương tác (Engagement Rate), hệ thống không gộp chung toàn bộ bệnh nhân vào một group lớn. Một người mẹ có con đang chỉnh nha tăng trưởng sẽ hoàn toàn không muốn đọc bài viết về kỹ thuật cắm cấy phục hình Implant cho người già. Do đó, mô hình thực chiến bắt buộc phải triển khai theo hình thức **Tiểu cộng đồng chuyên biệt (Micro-Communities)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cb9635d-4179-4fb8-b083-7fa580e15549','ef3b12ad-2e22-4294-9b4b-349ece77265d',49,'text','Dưới đây là quy trình chuẩn hóa 4 bước để thiết lập và kích hoạt một Tiểu cộng đồng vận hành tự động trong hệ thống của bạn:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('06c25dad-dcde-4af7-912f-571352e48e6a','18-patient-community','ef3b12ad-2e22-4294-9b4b-349ece77265d',4,'Phân đoạn và gắn Tag hệ thống:','phan-oan-va-gan-tag-he-thong',15,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('638be322-b364-48dd-bca4-c0d3aacba595','06c25dad-dcde-4af7-912f-571352e48e6a',50,'text','***Bước 1: Sàng lọc CRM.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bea007c2-1175-4e19-8bf4-e1a01955d2c5','06c25dad-dcde-4af7-912f-571352e48e6a',51,'text','Dựa vào dữ liệu lịch sử điều trị trên CRM, tiến hành lọc và gắn tag chính xác cho từng tệp bệnh nhân theo nhu cầu (Ví dụ: `Group_Phu_Huynh_Chinh_Nha`, `Group_Premium_Porcelain`).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a0eb3fdd-4d6d-4c1e-b2b4-5367501bff41','18-patient-community','ef3b12ad-2e22-4294-9b4b-349ece77265d',4,'Thiết lập hồ chứa và Quy tắc:','thiet-lap-ho-chua-va-quy-tac',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70529dc0-41b9-4df6-80ad-742383b7ccfa','a0eb3fdd-4d6d-4c1e-b2b4-5367501bff41',52,'text','***Bước 2: Lựa chọn nền tảng.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('61618fc1-f630-4569-beb0-3c4eefc5df25','a0eb3fdd-4d6d-4c1e-b2b4-5367501bff41',53,'text','Xây dựng các nhóm Zalo chăm sóc khách kín hoặc Group Facebook riêng tư. Thiết lập bộ quy tắc ứng xử của nhóm: không quảng cáo, không bán hàng chéo, chỉ chia sẻ tri thức và hỗ trợ y khoa trực tiếp từ Bác sĩ trưởng ca.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e381812a-6c7d-482f-b0ca-0c67405de595','18-patient-community','ef3b12ad-2e22-4294-9b4b-349ece77265d',4,'Lập lịch Content Pipeline tự động:','lap-lich-content-pipeline-tu-ong',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4ef7c672-769b-469b-9f15-80464365f651','e381812a-6c7d-482f-b0ca-0c67405de595',54,'text','***Bước 3: Số hóa nội dung giáo dục.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0ebeed0c-800d-402d-919d-557039a1f2ae','e381812a-6c7d-482f-b0ca-0c67405de595',55,'text','Đưa vào nhóm các chuỗi nội dung giáo dục hậu điều trị được thiết kế ngắn gọn, trực quan (E-book bỏ túi, video ngắn từ TikTok @thichlamrang). Giải đáp các thắc mắc thường gặp để giảm tải áp lực cho tổng đài.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('02e63043-69bc-4514-ab3b-fc5f3132b330','18-patient-community','ef3b12ad-2e22-4294-9b4b-349ece77265d',4,'Kích hoạt điểm chạm vật lý:','kich-hoat-iem-cham-vat-ly',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d03f028b-2a56-46d7-8758-07ccd4ac036b','02e63043-69bc-4514-ab3b-fc5f3132b330',56,'text','***Bước 4: Tổ chức Workshop định kỳ.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a3c9e8ef-bf23-4281-8223-388a76caa033','02e63043-69bc-4514-ab3b-fc5f3132b330',57,'text','Chuyển đổi tương tác từ không gian số sang đời thực. Tổ chức các buổi hội thảo nhỏ ngay tại sảnh chờ phòng khám (Ví dụ: Workshop kiểm soát khớp cắn cho tệp răng sứ; Ngày hội "Đồng niềng tỏa sáng").',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('414eb17e-aa49-4b22-bfe2-fc2211ef3b3f','02e63043-69bc-4514-ab3b-fc5f3132b330',58,'text','**Bí quyết vận hành Micro-Community:** Sức mạnh của tiểu cộng đồng nằm ở sự tương tác giữa các thành viên (Peer-to-Peer). Khi một bệnh nhân mới vào nhóm và hoang mang hỏi: *"Mới siết răng về đau quá có sao không các mẹ?"*, và nhận được lời trấn an từ 3 bệnh nhân cũ: *"Không sao đâu em, chị niềng ở Thích Làm Răng được 1 năm rồi, chỉ ê 2 ngày đầu thôi, sau đó ăn nhai thả ga"* lúc này, hệ thống cộng đồng đã tự động thay thế vai trò của một nhân viên tư vấn, neo giữ niềm tin của khách hàng ở mức tuyệt đối.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('da6611c1-2a05-4c36-81fa-cc1fa3d1ae69','18-patient-community',NULL,2,'18.5 Danh mục tài sản hệ thống (Community Assets)','185-danh-muc-tai-san-he-thong-community-assets',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('abbe83e5-7740-47aa-acea-0a8bbb8b80db','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',59,'text','**Bộ khung bảo vật phòng chống vận hành cảm tính**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6ef4109d-c922-437e-b36b-42d355577c33','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',60,'text','Trong quản trị vận hành nha khoa, có một câu nói cực kỳ kinh điển: *"Nếu bạn không thể đóng gói nó thành tài sản, bạn không thể nhân bản; nếu bạn không viết nó xuống thành quy trình, nhân sự sẽ làm việc bằng tâm trạng"*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7d080065-a579-4f11-8b42-206627a52977','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',61,'text','Xây dựng **Patient Community** không phải là việc hứng lên thì tặng quà, rảnh rỗi thì nhắn tin hỏi thăm. Nếu thiếu đi bộ khung tài sản hệ thống dưới đây, toàn bộ công sức chăm sóc của phòng khám RHM sẽ lập tức rơi vào cái bẫy cảm tính: hôm nào nhân sự vui thì tương tác nhiệt tình, hôm nào quá tải thì bỏ mặc khách hàng, dữ liệu đổ về CRM sẽ trở thành một mớ hỗn độn không thể đo lường hiệu quả (ROI).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cb89518-1625-43a7-8715-97a318ac2348','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',62,'text','Hệ điều hành **Dental Empire OS** quy định **7 tài sản tối thiểu** bắt buộc phải được thiết lập, số hóa và lưu trữ sẵn trên hệ thống dữ liệu chung của phòng khám trước khi kích hoạt bất kỳ chiến dịch cộng đồng nào:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3862b825-d583-419e-affe-4ae3b9961cd7','18-patient-community','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',3,'Ma trận đóng gói 7 tài sản cốt lõi của patient community','ma-tran-ong-goi-7-tai-san-cot-loi-cua-patient-community',20,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3419df36-19cf-494e-8cbb-fc853423c952','3862b825-d583-419e-affe-4ae3b9961cd7',63,'image',NULL,'book/18-patient-community/91e9dc62-2be0-4518-923b-924fcc39428f-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0a0b615e-2907-4ad2-9fb6-a348e32d4be6','18-patient-community','da6611c1-2a05-4c36-81fa-cc1fa3d1ae69',3,'Bóc tách chi tiết 3 tài sản chiến lược dòng tiền (The cashflow assets)','boc-tach-chi-tiet-3-tai-san-chien-luoc-dong-tien-the-cashflow-assets',21,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6794115c-e719-41ed-a956-de5ff242f310','18-patient-community','0a0b615e-2907-4ad2-9fb6-a348e32d4be6',5,'Tài sản 1: Kiến trúc một Recall Flow tự động (Chu kỳ 6 tháng)','tai-san-1-kien-truc-mot-recall-flow-tu-ong-chu-ky-6-thang',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('117da2c6-3a2e-4fb9-ab28-909b107f0fbf','6794115c-e719-41ed-a956-de5ff242f310',64,'text','Không để nhân viên tự nhớ lịch hẹn của khách. Hệ thống CRM bắt buộc phải lập trình một đường ống nhắc lịch tự động chạy ngầm, chia thành 3 điểm chạm thời gian:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('666d0db2-9ea4-42ec-9e1f-30fd2a5dd998','6794115c-e719-41ed-a956-de5ff242f310',65,'text','- **Điểm chạm T-7 ngày:** Hệ thống tự động bắn tin nhắn Zalo OA ZNS thông báo: *"Chào anh/chị, chỉ còn 7 ngày nữa là đến hạn tầm soát răng miệng định kỳ 6 tháng để bảo vệ thành quả nụ cười sứ. Bác sĩ Vinh đã chừa sẵn cho mình một khung giờ đặc quyền vào..."*- **Điểm chạm T-3 ngày:** Nhân viên CSKH thực hiện cuộc gọi kiểm tra trạng thái và chốt lịch hẹn chính thức trên hệ thống, gắn tag `Confirmed_Recall`.- **Điểm chạm T-1 ngày:** Hệ thống nhắn tin nhắc lại số ghế, khung giờ và tên Bác sĩ phụ trách kèm sơ đồ đường đi phòng khám để tối ưu tỷ lệ No-show.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e8446d34-6f60-41fb-a732-40e52afc0695','18-patient-community','0a0b615e-2907-4ad2-9fb6-a348e32d4be6',5,'Tài sản 2: Chiến lược Phá băng bằng Reactivation Flow','tai-san-2-chien-luoc-pha-bang-bang-reactivation-flow',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f9dfe1ba-83f0-4ca7-ad05-846c546890ac','e8446d34-6f60-41fb-a732-40e52afc0695',66,'text','Đối với những bệnh nhân đã điều trị xong nhưng ngắt kết nối hoàn toàn với phòng khám từ 12 đến 24 tháng, tuyệt đối không bốc máy lên gọi điện chào mời mua dịch vụ mới. Hãy áp dụng **Kịch bản phá băng dựa trên sự tử tế y khoa**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f396207f-c51b-4dce-96ef-74c8d60dcb7f','e8446d34-6f60-41fb-a732-40e52afc0695',67,'text','*"Chào anh/chị **[Tên_Bệnh_Nhân]**, em là **[Tên_CSKH]** từ nha khoa **[Tên_Phòng_Khám]** ạ. Đã lâu rồi phòng khám chưa được gặp lại anh/chị qua kiểm tra răng định kỳ. Bác sĩ **[Tên_Bác_Sĩ]** khi kiểm tra lại hồ sơ bệnh án cũ có dặn em phải liên hệ hỏi thăm xem hiện tại tình trạng ăn nhai của mình có gặp khó khăn gì không, và có răng nào bị ê buốt khi uống nước đá không ạ?',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5086d9ba-ca12-4851-93ae-9485eef26400','e8446d34-6f60-41fb-a732-40e52afc0695',68,'text','Nhân dịp tháng tri ân cựu bệnh nhân, Bác sĩ có ký tặng riêng cho mình một suất ''Tái tầm soát cấu trúc răng toàn diện miễn phí 100%'' tại phòng khám. Anh/chị thong thả sắp xếp thời gian qua để Bác sĩ chụp lại phim, kiểm tra độ khít sát của răng xem có vấn đề gì không nhé ạ."*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4d0e94a4-d4e0-4dc3-8082-080fdd68dea7','18-patient-community','0a0b615e-2907-4ad2-9fb6-a348e32d4be6',5,'Tài sản 3: Bộ khung Patient Education Calendar (Lịch giáo dục nụ cười)','tai-san-3-bo-khung-patient-education-calendar-lich-giao-duc-nu-cuoi',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('661b7bb4-654f-41d8-b2f1-eac4f1c79c99','4d0e94a4-d4e0-4dc3-8082-080fdd68dea7',69,'text','Để khách hàng không quên bạn, thương hiệu của bạn phải xuất hiện đều đặn trong cuộc sống của họ với tư cách là một chuyên gia mang lại giá trị thực, chứ không phải một kẻ đi móc túi. Đóng gói lịch phát sóng nội dung theo công thức **30/70**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e5bc5a1-bcaa-44e3-aba5-ccd7cbb81761','4d0e94a4-d4e0-4dc3-8082-080fdd68dea7',70,'text','- **70% Nội dung hữu ích (Value Content):** Các bài viết, Infographic, Video ngắn từ TikTok `@thichlamrang` giải đáp các thắc mắc thường gặp: *"Trẻ em bao nhiêu tuổi thì nên đi tầm soát niềng răng?"*, *"Răng sứ bị chảy máu nướu thì phải xử lý thế nào tại nhà?"*.- **30% Nội dung thương hiệu (Brand Content):** Chia sẻ các câu chuyện lâm sàng chuẩn hóa (**Clinical Case Study**), không khí nhộn nhịp tại các buổi Workshop, hình ảnh Bác sĩ đi tu nghiệp nước ngoài để củng cố tầng *Authority Check*.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dd8ab105-ae70-408a-a356-adb3ea889b0c','4d0e94a4-d4e0-4dc3-8082-080fdd68dea7',71,'text','**Mantra tối thượng cho Nhà quản trị:** Khi bạn sở hữu đầy đủ 7 tài sản này trong tay, Patient Community của phòng khám sẽ biến thành một đường ống vận hành chuẩn xác. Nhân sự mới vào chỉ cần nhìn vào ma trận tài sản để thực thi, ban giám đốc chỉ cần nhìn vào Dashboard để kiểm soát chỉ số, đưa phòng khám bước vào trạng thái tăng trưởng hữu cơ an toàn, bền vững và khoa học.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8370d5cb-0074-42de-85db-d88084ab78d6','18-patient-community',NULL,2,'18.6 Hành trình chủ đích','186-hanh-trinh-chu-ich',25,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d2b5a671-a3be-4365-babc-170d163c3baa','8370d5cb-0074-42de-85db-d88084ab78d6',72,'text','**Quy trình vận hành chuẩn của Pipeline Community**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('70e5a465-3af9-4a41-94ce-d16b39f9683e','8370d5cb-0074-42de-85db-d88084ab78d6',73,'text','Để biến những định hướng chiến lược thành kết quả thực tế, hệ điều hành **Dental Empire OS** không cho phép nhân sự vận hành cộng đồng một cách mơ hồ. Mọi bệnh nhân sau khi bước ra khỏi phòng điều trị phải được tự động đưa vào một đường ống hành trình có lộ trình rõ ràng, có chủ đích và được lập trình chặt chẽ trên hệ thống.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5df6c363-c76c-4008-8fcc-748ce4199f60','8370d5cb-0074-42de-85db-d88084ab78d6',74,'text','Quy trình vận hành chuẩn của phân hệ **Patient Community** được thiết kế thành một chuỗi vòng lặp khép kín gồm 7 bước tuyến tính:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3c8607d7-bbb0-4838-8047-876064e542dc','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Hoàn tất điều trị lâm sàng:','hoan-tat-ieu-tri-lam-sang',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9d41068f-7d65-453d-b6e7-d76922305ecb','3c8607d7-bbb0-4838-8047-876064e542dc',75,'text','***Điểm khởi đầu hành trình.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('47585b72-c764-4733-a166-8098fe9ac891','3c8607d7-bbb0-4838-8047-876064e542dc',76,'text','Bệnh nhân hoàn thành phân hệ điều trị chính (gắn sứ, tháo niềng, nghiệm thu Implant). Toàn bộ dữ liệu lâm sàng cuối cùng được ký duyệt và đóng lại từ Clinic OS.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d7ac34d-d8fb-4a26-9114-462a0a1eba42','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Phân nhóm bệnh nhân thông minh:','phan-nhom-benh-nhan-thong-minh',27,'[]');
