INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d899ce79-95fc-45f9-b5f1-7aee6d8afd86','7d7ac34d-d8fb-4a26-9114-462a0a1eba42',78,'text','Hệ thống tự động quét hồ sơ, phân loại bệnh nhân vào các nhóm chuyên biệt (Ví dụ: theo dịch vụ, độ tuổi, LTV) và gắn các thẻ Tag nhận diện tương ứng.',NULL,NULL,NULL,NULL,NULL);
