INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fae68129-aca4-4db5-bd66-b593a5ed4843','33f6ade7-9355-4ad1-be2d-677876dfb4f1',79,'text','***Lập trình đường ống thời gian.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7e65e812-b5cb-434d-b7f3-d3a515b47a02','33f6ade7-9355-4ad1-be2d-677876dfb4f1',80,'text','Thiết lập chuỗi lịch hẹn chăm sóc chủ động và nhắc lịch tái khám định kỳ (3 tháng, 6 tháng) dựa trên chu kỳ sinh học của từng nhóm bệnh lý.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0732f3ef-35c8-4719-adee-0643fcad7611','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Nuôi dưỡng bằng nội dung giáo dục:','nuoi-duong-bang-noi-dung-giao-duc',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2c66fc96-0984-4d54-bc41-880c3cd41dae','0732f3ef-35c8-4719-adee-0643fcad7611',81,'text','***Duy trì điểm chạm tự nhiên.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ef9131a9-ebe7-4519-9359-26401cd1ec5a','0732f3ef-35c8-4719-adee-0643fcad7611',82,'text','Tự động phân phối các bài viết, cẩm nang số và video ngắn từ kho nội dung giáo dục thường thức đến kênh liên lạc của bệnh nhân, giúp họ bảo tồn kết quả điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('65727f38-7b84-4b88-a877-a223185296a0','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Kích hoạt chiến dịch tái khám:','kich-hoat-chien-dich-tai-kham',30,'[]');
