INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5dc648fa-bc9f-44bf-a1f7-d9e4a9bbbd5d','65727f38-7b84-4b88-a877-a223185296a0',84,'text','Khi đến mốc thời gian quy định, hệ thống kích hoạt kịch bản phá băng hoặc kịch bản nhắc lịch để điều hướng bệnh nhân đặt lịch hẹn quay lại phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('03e56d38-7748-49f8-a4ef-28d5bbbc7e3b','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Tích hợp vào Membership &amp; Community:','tich-hop-vao-membership-amp-community',31,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('955e71cd-74c8-4e7f-a443-6320ef62b8d6','03e56d38-7748-49f8-a4ef-28d5bbbc7e3b',85,'text','***Nâng cấp vị thế thành viên.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0bd32de6-3db1-448c-8a6c-107886922a6a','03e56d38-7748-49f8-a4ef-28d5bbbc7e3b',86,'text','Mời bệnh nhân gia nhập vào các tiểu cộng đồng chuyên biệt (Micro-Communities) và kích hoạt tài khoản thẻ hội viên VIP để họ hưởng các đặc quyền phi y khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1f0c42f9-a473-4dd9-9c14-87ea257bd577','18-patient-community','8370d5cb-0074-42de-85db-d88084ab78d6',3,'Thu hoạch giá trị cuối hành trình:','thu-hoach-gia-tri-cuoi-hanh-trinh',32,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('539410c3-1a35-49c3-a81d-27a8f7179e9c','1f0c42f9-a473-4dd9-9c14-87ea257bd577',87,'text','***Tối ưu hóa chỉ số LTV.***',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d95c0b7-94ea-4ace-b138-7593b5520d9c','1f0c42f9-a473-4dd9-9c14-87ea257bd577',88,'text','Khai thác tài sản lòng tin của cộng đồng để chuyển hóa thành các bài review chất lượng, dòng khách giới thiệu (Referral) dồi dào hoặc các lượt tái sử dụng dịch vụ (Repeat Visit).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('741f71b0-5dc9-46dc-9ced-bdf63b90fec3','18-patient-community',NULL,2,'18.7 Các lỗi chí mạng trong vận hành Patient Community (The retention pitfalls)','187-cac-loi-chi-mang-trong-van-hanh-patient-community-the-retention-pitfalls',33,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('90c517f9-7d59-4f9f-b1a2-66fb1e726174','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',89,'text','Trong quá trình dịch chuyển bộ máy vận hành từ tư duy săn bắn (tìm khách mới) sang tư duy nuôi dưỡng (giữ khách cũ), phần lớn các phòng khám RHM hiện nay đều mắc phải những sai lầm mang tính hệ thống. Những lỗ hổng này âm thầm tiêu tốn ngân sách Marketing, làm rò rỉ tài nguyên dữ liệu và tự tay cắt đứt sợi dây liên kết niềm tin với bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a09df69-ce8d-4789-956e-79d4fab002b6','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',90,'text','Hệ điều hành **Dental Empire OS** chỉ ra hai nhóm lỗi cốt lõi: **Sự thờ ơ sau điều trị** và **Sự cẩu thả trong trải nghiệm thông tin**. Phân tích chi tiết bốn khối lỗi phổ biến:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('036615e6-347d-497d-b09f-bea6c565cbaf','18-patient-community','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',3,'Lỗi 1: Hội chứng "Đem con bỏ chợ"','loi-1-hoi-chung-em-con-bo-cho',34,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f0dfb377-f4d4-495d-a907-5bed240a9a3a','036615e6-347d-497d-b09f-bea6c565cbaf',91,'text','**Điều trị xong là mất liên lạc & Không nhắc tái khám**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('76211185-b585-43e5-8770-a941265db211','036615e6-347d-497d-b09f-bea6c565cbaf',92,'text','Đây là căn bệnh trầm kha của các nha khoa chạy theo doanh số ngắn hạn. Ngay khi bệnh nhân thanh toán xong hóa đơn và bước ra khỏi cửa, họ lập tức biến mất khỏi tâm trí của đội ngũ vận hành.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('59ab4b65-4cea-4131-b218-c97fc5c613b6','036615e6-347d-497d-b09f-bea6c565cbaf',93,'text','- **Biểu hiện:** Không có lịch trình hỏi thăm, không có hệ thống tự động tính chu kỳ sinh học để nhắc lịch tái khám định kỳ (Recall). Phòng khám hoàn toàn thụ động chờ đợi cho đến khi răng bệnh nhân có vấn đề hoặc đau đớn trở lại thì họ mới tự tìm đến (hoặc tệ hơn là họ đã sang phòng khám đối thủ).- **Hậu quả:** Bệnh nhân cảm thấy mình chỉ là một công cụ tạo doanh thu. Bộ lọc hoài nghi kích hoạt và phá hủy toàn bộ những trải nghiệm tốt đẹp trước đó trên ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cb2b9ec8-1bd4-46ae-a36c-6a571388074a','18-patient-community','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',3,'Lỗi 2: Tư duy cào bằng','loi-2-tu-duy-cao-bang',35,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('10a87375-d85d-4f61-8e67-61d85de5b712','cb2b9ec8-1bd4-46ae-a36c-6a571388074a',94,'text','**Không phân nhóm bệnh nhân & Gửi tin nhắn chăm sóc chung chung**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('432cf2ba-7402-4002-8895-d3e30f9e2968','cb2b9ec8-1bd4-46ae-a36c-6a571388074a',95,'text','Nhiều phòng khám có ý thức chăm sóc khách hàng cũ, nhưng lại thực hiện bằng phương pháp thô sơ và lười biếng: dùng một kịch bản tin nhắn duy nhất để bắn (Broadcast) hàng loạt cho toàn bộ tệp dữ liệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1777a0a6-8dad-4a31-8246-220afeb64b61','cb2b9ec8-1bd4-46ae-a36c-6a571388074a',96,'text','- **Biểu hiện:** Một tin nhắn chúc mừng ngày lễ hoặc hướng dẫn răng miệng chung chung được gửi đồng thời cho một bạn trẻ đang niềng răng, một doanh nhân vừa làm 20 răng sứ thẩm mỹ, và một cụ già 70 tuổi vừa cấy Implant All-on-4.- **Hậu quả:** **Gãy ngữ cảnh tâm lý (Contextual Broken).** Khách hàng thấy nội dung không liên quan đến nỗi đau hay nhu cầu thực tế của họ. Phản xạ tự nhiên của họ là lướt qua, xóa tin nhắn, hoặc nhấn nút "Hủy quan tâm" Zalo OA vì cảm thấy bị làm phiền bởi tin nhắn rác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('5c7dd126-7677-485f-8ef2-e01f77216292','18-patient-community','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',3,'Lỗi 3: Kho khoảng trống hệ sinh thái','loi-3-kho-khoang-trong-he-sinh-thai',36,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('fb097295-6eaa-44a6-adb8-6b72ea2745fb','5c7dd126-7677-485f-8ef2-e01f77216292',97,'text','**Không chương trình khách cũ, Không Membership, Không Cộng đồng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('333b536e-0f6a-4326-857d-036745b073ef','5c7dd126-7677-485f-8ef2-e01f77216292',98,'text','Phòng khám vận hành mà không có một "hồ chứa cảm xúc" và quyền lợi để giữ chân khách hàng ở lại dài hạn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0cf47d3f-5e0e-48ff-a459-edc4c6b7b13b','5c7dd126-7677-485f-8ef2-e01f77216292',99,'text','- **Biểu hiện:** Thiếu vắng hoàn toàn các chính sách đặc quyền dành riêng cho người đã sử dụng dịch vụ (Old Patient Campaign); không có cấu trúc phân tầng thẻ hội viên (Membership Plan) để tri ân tích lũy; không thiết lập các tiểu cộng đồng (Micro-Communities) như hội phụ huynh chỉnh nha hay cộng đồng răng sứ để khách hàng giao lưu, kết nối.- **Hậu quả:** Khách hàng cũ không có lý do, không có động lực và không có bất kỳ rào cản lợi ích nào để trung thành với bạn. Họ sẵn sàng rời đi ngay khi có một phòng khám khác chào mời mức giá rẻ hơn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('14ff0c85-bac2-4c8e-a560-dfdc63b49e7c','18-patient-community','741f71b0-5dc9-46dc-9ced-bdf63b90fec3',3,'Lỗi 4: Mù mờ chỉ số tài chính','loi-4-mu-mo-chi-so-tai-chinh',37,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c87356d7-cf43-486b-a22f-8dd42a513e6c','14ff0c85-bac2-4c8e-a560-dfdc63b49e7c',100,'text','**Hoàn toàn không đo lường doanh thu từ khách cũ**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5bbd5511-5816-402c-94ca-e28018cad455','14ff0c85-bac2-4c8e-a560-dfdc63b49e7c',101,'text','Ban giám đốc và bộ phận kế toán chỉ chăm chăm nhìn vào các chỉ số doanh thu tổng hoặc doanh thu từ các chiến dịch chạy Ads kiếm khách mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6eabe199-7906-4cb2-a8c2-8aecde1225d8','14ff0c85-bac2-4c8e-a560-dfdc63b49e7c',102,'text','- **Biểu hiện:** Trên Dashboard tài chính của *Finance OS* không hề cấu hình trường dữ liệu `Revenue_From_Old_Patients` (Doanh thu từ khách hàng cũ). Nhà quản trị không biết trong tháng có bao nhiêu tiền đổ về từ việc khách cũ quay lại làm thêm dịch vụ (Cross-sell/Up-sell), mua sản phẩm Homecare hoặc đăng ký gói hội viên gia đình.- **Hậu quả:** Phòng khám tiếp tục rơi vào vòng xoáy nghiện quảng cáo. Bạn liên tục đốt tiền tăng ngân sách Paid Ads (tăng CAC) để mua khách mới, trong khi đang ngồi trên một mỏ vàng dữ liệu khách cũ có chi phí khai thác bằng 0 nhưng biên lợi nhuận thuần cao gấp 5 lần.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('859de959-2e0d-4dd8-b5ad-b18862a8baec','18-patient-community',NULL,2,'18.8 Mối liên kết hệ sinh thái','188-moi-lien-ket-he-sinh-thai',38,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4df9815b-a431-474c-8fdb-71954be80ac1','859de959-2e0d-4dd8-b5ad-b18862a8baec',103,'text','**Trục giao thoa của cỗ máy tăng trưởng toàn diện**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f322e0f1-ef25-47ed-90a2-8ae2f2b9d970','859de959-2e0d-4dd8-b5ad-b18862a8baec',104,'text','Trong cấu trúc tổng thể của **Dental Empire OS**, **Patient Community** tuyệt đối không phải là một module hoạt động độc lập hay tách rời. Nếu bạn xem cộng đồng là một phân hệ cô lập, nó sẽ nhanh chóng kiệt quệ vì thiếu nguồn nuôi dưỡng hoặc không thể chuyển hóa giá trị thành bài toán kinh tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('13e97c81-6ff2-40e9-9e4d-59a50a37734a','859de959-2e0d-4dd8-b5ad-b18862a8baec',105,'text','Bản chất của một hệ sinh thái nha khoa phát triển bền vững là **Tính hợp nhất (Unified Integration)**. Tầng cộng đồng đóng vai trò là "trạm trung chuyển cảm xúc và hành vi", kết nối trực tiếp với 3 phân hệ cốt lõi: **Patient Experience (Trải nghiệm khách hàng)**, **Referral Ecosystem (Hệ sinh thái giới thiệu)**, và **Education / Product Layer (Tầng giáo dục & Sản phẩm phụ trợ)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d6096bcc-9e5f-408b-842b-f96775a945fb','18-patient-community','859de959-2e0d-4dd8-b5ad-b18862a8baec',3,'Nối với Patient Experience','noi-voi-patient-experience',39,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eec56837-460c-4aa6-bc02-3d318f8f0d8e','d6096bcc-9e5f-408b-842b-f96775a945fb',106,'text','**Gốc rễ sinh ra cộng đồng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2a7b9fe3-da8f-472e-a11d-197dfef17622','d6096bcc-9e5f-408b-842b-f96775a945fb',107,'text','- **Mối liên kết:** Trải nghiệm lâm sàng và dịch vụ xuất sắc tại ghế nha chính là nhiên liệu đầu vào duy nhất để xây dựng cộng đồng. Bạn không thể kéo bệnh nhân vào một nhóm hội viên nếu họ bước ra khỏi phòng khám với một cơn đau không được xử lý hoặc một sự bực dọc về thái độ của lễ tân.- **Hệ quả vận hành:** Khi bệnh nhân được chăm sóc tốt vượt mong đợi, họ sẽ mang trạng thái cảm xúc tích cực đó gia nhập vào cộng đồng với một tâm lý cởi mở, sẵn sàng tương tác và bảo vệ thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4eca73b9-6f4e-4583-89a9-407e06229631','18-patient-community','859de959-2e0d-4dd8-b5ad-b18862a8baec',3,'Nối với Education / Product Layer','noi-voi-education-product-layer',40,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5fc19e9b-ebf0-4a60-a61c-304ea164ed72','4eca73b9-6f4e-4583-89a9-407e06229631',108,'text','**Công cụ giữ nhiệt và Khai thác giá trị**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a7d38b40-d5e1-4b8a-b217-acd4c23d22d1','4eca73b9-6f4e-4583-89a9-407e06229631',109,'text','- **Mối liên kết:** Cộng đồng là không gian hoàn hảo để phòng khám phân phối các tài sản tri thức và giải pháp sản phẩm Homecare mà không tạo cảm giác khiên cưỡng.- **Hệ quả vận hành:** Patient Community giữ vai trò nuôi dưỡng thông tin, giúp bệnh nhân liên tục được cập nhật kiến thức giáo dục thường thức. Từ nền tảng tri thức đó, họ sẽ phát sinh nhu cầu mua sắm các sản phẩm chăm sóc răng chuyên sâu tại nhà hoặc chủ động xuống tiền cho các gói Membership gia đình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('27b50d47-f047-402e-96dc-fa34663fd771','18-patient-community','859de959-2e0d-4dd8-b5ad-b18862a8baec',3,'Nối với Referral Ecosystem','noi-voi-referral-ecosystem',41,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c1b71e4f-9d16-423e-b53c-9de46cad7782','27b50d47-f047-402e-96dc-fa34663fd771',110,'text','**Kích nổ vòng lặp tăng trưởng vô cực**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cf4b850c-a7d1-441a-a66e-dc02872025f5','27b50d47-f047-402e-96dc-fa34663fd771',111,'text','- **Mối liên kết:** Một thành viên cộng đồng được giáo dục tốt và có trải nghiệm gắn kết lâu dài sẽ tự động chuyển hóa thành một "Đại sứ thương hiệu" (Ambassador).- **Hệ quả vận hành:** Vòng lặp hành vi được lập trình hoàn hảo theo trục dọc:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a291343-807c-407c-b796-3f18fa970e02','27b50d47-f047-402e-96dc-fa34663fd771',112,'text','\\text{Chăm sóc tốt} \\longrightarrow \\text{Dễ quay lại (Repeat Visit)} \\longrightarrow \\text{Dễ để lại Review (Social Proof)} \\longrightarrow \\text{Dễ giới thiệu người khác (Referral)}',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3a764dc8-6184-40ee-abfc-06bb93bce54d','27b50d47-f047-402e-96dc-fa34663fd771',113,'text','Hệ sinh thái Referral sẽ liên tục có dòng lead mới đổ về, và những lead mới này sau khi điều trị xong lại tiếp tục được Patient Community thu nạp, tạo thành một động cơ tăng trưởng hữu cơ không bao giờ dừng lại.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cc452a1b-7a26-4c58-8eb0-920e1e2c2956','18-patient-community',NULL,2,'18.9 Output cần có','189-output-can-co',42,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1159d1b2-3ce5-4595-95ec-c7d9d39764de','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',114,'text','Ý tưởng dù có hay đến đâu cũng sẽ tan biến nếu không được đóng gói thành các tài liệu có cấu trúc. Để chuyển hóa toàn bộ tư duy chiến lược của chương **Patient Community** thành bộ máy tự chạy tại phòng khám RHM, đội ngũ vận hành bắt buộc phải hoàn thiện và nghiệm thu **Bộ 7 đầu ra tiêu chuẩn (Deliverables Bundle)** dưới đây.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8c00d5b9-9e7c-4701-91c3-e324432ef707','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',115,'image',NULL,'book/18-patient-community/b3c5254a-a5f7-4159-b2b4-e9bf619891ec-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6a923afa-4da9-4adb-ab8f-84e529f8f6f5','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',116,'text','Đây chính là bộ khung xương sống kỹ thuật giúp phòng khám số hóa lòng trung thành và quản trị giá trị vòng đời khách hàng một cách khoa học:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f5d6c836-132d-463f-8b96-2d1456c97c6d','18-patient-community','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',3,'Patient Segmentation Sheet (Bảng cấu trúc phân đoạn dữ liệu)','patient-segmentation-sheet-bang-cau-truc-phan-oan-du-lieu',43,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('44d63d16-a626-4e09-8087-37edf8853e81','f5d6c836-132d-463f-8b96-2d1456c97c6d',117,'text','Đầu ra này là một file Master dữ liệu (Excel hoặc cấu hình trực tiếp trên CRM) quy định chính xác cách gắn tag tự động để phân loại bệnh nhân ngay khi họ đóng ca lâm sàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('1d1634b7-786a-4676-a110-378e7dcb724e','18-patient-community','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',3,'Automated Recall Flow (Sơ đồ đường ống nhắc lịch chu kỳ)','automated-recall-flow-so-o-uong-ong-nhac-lich-chu-ky',44,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('15de3da7-fa93-4d1e-be72-c5be1899238b','1d1634b7-786a-4676-a110-378e7dcb724e',118,'text','Bản thiết kế luồng công việc (Workflow Blueprint) được lập trình sẵn trên CRM, tự động kích hoạt dựa trên mốc thời gian sinh học của răng miệng sau khi hoàn tất điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('acf61e14-d204-485c-982b-1a97ba1a5d62','18-patient-community','1d1634b7-786a-4676-a110-378e7dcb724e',5,'Điểm chạm 1: Zalo OA ZNS','iem-cham-1-zalo-oa-zns',45,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('be2a6ac4-d0ba-429e-8854-8f29d6184684','acf61e14-d204-485c-982b-1a97ba1a5d62',119,'text','*T - 7 Ngày.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e5e2e8fd-cd6e-4dd9-83a2-8ea321fae247','acf61e14-d204-485c-982b-1a97ba1a5d62',120,'text','Hệ thống tự động bắn tin nhắn cá nhân hóa thông báo đến hạn bảo dưỡng nụ cười. Cung cấp sẵn nút bấm "Đặt lịch ngay" để giảm ma sát thao tác.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4f8b20d9-19cf-4f71-8405-015dac63aeab','18-patient-community','1d1634b7-786a-4676-a110-378e7dcb724e',5,'Điểm chạm 2: Telesale Task Allocation','iem-cham-2-telesale-task-allocation',46,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d8f272dd-0bfd-4716-a12c-4c37d1109cc8','4f8b20d9-19cf-4f71-8405-015dac63aeab',121,'text','*T - 3 Ngày.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('febe4dd4-66c4-4961-8369-9534b3837639','4f8b20d9-19cf-4f71-8405-015dac63aeab',122,'text','Nếu khách chưa đặt lịch ở Bước 1, CRM tự động đẩy một tác vụ (Task) xuống cho nhân viên CSKH bốc máy gọi điện chăm sóc và chốt giờ hẹn tại ghế nha.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('6dacd103-5af6-4b9e-9ec1-e2d68381719d','18-patient-community','1d1634b7-786a-4676-a110-378e7dcb724e',5,'Điểm chạm 3: Confirmation &amp; Chỉ đường','iem-cham-3-confirmation-amp-chi-uong',47,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0a1bf451-3d86-4672-aefa-d9748641bee2','6dacd103-5af6-4b9e-9ec1-e2d68381719d',123,'text','*T - 1 Ngày.*',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('aa7d76e0-9a66-4aa0-9d78-1e39896c2f12','6dacd103-5af6-4b9e-9ec1-e2d68381719d',124,'text','Hệ thống bắn tin nhắn chốt số ghế, tên Bác sĩ phụ trách, khung giờ chính xác kèm sơ đồ đường đi Google Maps của phòng khám để tối ưu tỷ lệ No-show.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2abd06c9-1fe1-4d2d-8ae7-55512c7d411d','18-patient-community','cc452a1b-7a26-4c58-8eb0-920e1e2c2956',3,'Reactivation Flow (Đường ống kịch bản phá băng khách cũ)','reactivation-flow-uong-ong-kich-ban-pha-bang-khach-cu',48,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e256500-232d-4dd8-8408-35abc340b2ac','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',125,'text','Bộ tài liệu chứa các kịch bản mẫu (SMS, Zalo, Call Script) và quy trình xử lý từ xa để kết nối lại với tệp khách hàng "ngủ đông" đã ngắt kết nối với phòng khám trên 12 tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('92be686c-b41c-4979-b39c-6aba95a153fb','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',126,'text','**Triết lý cốt lõi:** Tuyệt đối không bán hàng chèo kéo. Chỉ sử dụng **Sự tử tế y khoa** và **Lý do chuyên môn** để phá băng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('eb0bc5f4-c593-4c70-a42a-dcc6bb230310','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',127,'text','- *Công cụ kích nổ:* Tặng một suất "Tái tầm soát cấu trúc răng toàn diện bằng công nghệ chụp phim CT Cone Beam miễn phí 100% từ Bác sĩ trưởng ca" gửi đích danh cho cựu bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7f87a26c-3552-465d-9eef-1528dcf4d920','18-patient-community','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',4,'Membership Plan (Chính sách phân tầng đặc quyền hội viên)','membership-plan-chinh-sach-phan-tang-ac-quyen-hoi-vien',49,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f8df4e99-fcb3-4bf5-b974-eba7bac2d7b9','7f87a26c-3552-465d-9eef-1528dcf4d920',128,'text','Bản cấu trúc phân chia quyền lợi kinh tế và đặc quyền trải nghiệm phi y khoa nhằm gia tăng chi phí chuyển đổi tâm lý của khách hàng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('97bcfab0-4d4f-487d-bffa-d35ec17b06b1','7f87a26c-3552-465d-9eef-1528dcf4d920',129,'text','- **Hạng Silver (Tích lũy <20 triệu):** Miễn phí cạo vôi răng 1 lần/năm; giảm 5% các dịch vụ phát sinh.- **Hạng Gold (Tích lũy 20 - 100 triệu):** Miễn phí cạo vôi răng trọn năm cho cá nhân; ưu tiên đặt lịch hẹn đích danh Bác sĩ; tặng set quà Homecare cao cấp (máy tăm nước sóng siêu âm).- **Hạng Diamond (Tích lũy >100 triệu hoặc giới thiệu ca lớn):** Nâng cấp lên đặc quyền **Family Pass** (Miễn phí cạo vôi răng trọn năm cho cả gia đình 4 người); nhận quà tặng phong cách sống vào các ngày lễ lớn; sử dụng phòng chờ VIP độc quyền tại nha khoa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('61ff5ff9-d0f9-4a8b-952a-1f8f32e0797e','18-patient-community','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',4,'Patient Education Calendar (Lịch giáo dục nụ cười thường thức)','patient-education-calendar-lich-giao-duc-nu-cuoi-thuong-thuc',50,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('0d55f164-c043-454c-a776-ae8e8f92dee5','61ff5ff9-d0f9-4a8b-952a-1f8f32e0797e',130,'text','Ma trận nội dung số được lập lịch phát sóng định kỳ hằng tháng trên các kênh truyền thông chủ lực (Zalo OA, Website TikTok) nhằm nuôi dưỡng tri thức cho cộng đồng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9c9351df-f2fd-4951-bcff-dd2d99816e59','61ff5ff9-d0f9-4a8b-952a-1f8f32e0797e',131,'text','- **Tuần 1 (Bảo tồn kết quả):** Kỹ thuật chăm sóc nướu sau gắn sứ; cách sử dụng chỉ nha khoa cho người niềng.- **Tuần 2 (Tầm soát gia đình):** Cẩm nang nhận biết thời điểm vàng chỉnh nha tăng trưởng cho trẻ em từ 6 - 12 tuổi.- **Tuần 3 (Clinical Storytelling):** Đăng tải một **Clinical Case Study** chuẩn hóa kể về hành trình lột xác diện mạo của một cựu bệnh nhân để kích hoạt niềm tin.- **Tuần 4 (Tương tác trực tuyến):** Chuyên mục "Bác sĩ Vinh trả lời" — Giải đáp 10 câu hỏi nhức nhối về răng miệng do các thành viên cộng đồng gửi về trong tháng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('b785f0a6-bd27-4471-bc75-d17b8378a01d','18-patient-community','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',4,'Community Plan (Kế hoạch vận hành bộ tộc nụ cười)','community-plan-ke-hoach-van-hanh-bo-toc-nu-cuoi',51,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b05258a6-ef1e-4fc6-a27b-21de4692230d','b785f0a6-bd27-4471-bc75-d17b8378a01d',132,'text','Bản kế hoạch chi tiết về cách thức duy trì và tăng trưởng chỉ số tương tác (Engagement) bên trong các nhóm Micro-Communities.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('7a4aab9b-c4da-402a-b860-2759d5e33118','b785f0a6-bd27-4471-bc75-d17b8378a01d',133,'text','- **Quy tắc ngầm (Group Rules):** Thiết lập rào cản kiểm duyệt: Không spam quảng cáo, không chia sẻ nội dung tiêu cực, mọi câu hỏi lâm sàng bắt buộc phải được Bác sĩ hoặc Trợ thủ có chuyên môn phản hồi trong vòng 15 phút.- **Điểm chạm vật lý (Offline Workshop):** Lên lịch tổ chức các buổi hội thảo nhỏ hằng quý ngay tại sảnh chờ phòng khám (Ví dụ: Ngày hội "Mẹ bỉm thông thái - Chăm răng chuẩn khoa học cho con").',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7f4d6f79-8d15-4834-819b-3ab041d6146c','18-patient-community','2abd06c9-1fe1-4d2d-8ae7-55512c7d411d',4,'Old Patient Campaign (Ma trận chiến dịch kích nổ doanh số khách cũ)','old-patient-campaign-ma-tran-chien-dich-kich-no-doanh-so-khach-cu',52,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c71f11bb-a667-4ec6-aca1-c9652dd723a2','7f4d6f79-8d15-4834-819b-3ab041d6146c',134,'text','Danh mục các chương trình tiếp thị nội bộ được kích hoạt định kỳ (vào mùa thấp điểm hoặc các dịp lễ lớn) nhằm khai thác doanh thu up-sell/cross-sell từ nguồn khách cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('719ea1bf-2582-4f63-a4e9-b846c6f5d63c','7f4d6f79-8d15-4834-819b-3ab041d6146c',135,'text','- **Chiến dịch "Family Day - Gắn kết nụ cười tổ ấm":** Khách hàng cũ dắt người thân đi cùng sẽ được tặng gói kiểm tra tổng quát miễn phí và tài trợ 10% chi phí điều trị cho người đi cùng.- **Chiến dịch "Bảo hành chủ động":** Mời tệp khách làm răng sứ thẩm mỹ quay lại kiểm tra định kỳ, tặng kèm dịch vụ spa chăm sóc da mặt hoặc voucher nghỉ dưỡng phi y khoa cao cấp để tạo hiệu ứng Wow Peak hậu điều trị.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4f9b559c-980e-4c99-a77d-e8b1883468aa','18-patient-community',NULL,2,'18.10 Kết luận - Patient Community là pháo đài giữ chân và động cơ tăng trưởng hữu cơ','1810-ket-luan-patient-community-la-phao-ai-giu-chan-va-ong-co-tang-truong-huu-co',53,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('4b8900de-4d1a-4d38-9fef-a3066e74f9c5','4f9b559c-980e-4c99-a77d-e8b1883468aa',136,'text','Để kết lại toàn bộ chương **Patient Community**, có một sự thật cốt lõi mà mọi nhà quản trị hệ thống **Dental Empire OS** phải thuộc nằm lòng: **Một phòng khám RHM chỉ thực sự trưởng thành khi doanh thu thuần đến từ khách hàng cũ bắt đầu vượt qua chi phí đổ vào để mua khách hàng mới.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ff1d8afe-09c4-43a3-a491-100d0eb5b501','4f9b559c-980e-4c99-a77d-e8b1883468aa',137,'text','Tầng Cộng đồng chính là phòng tuyến tối cao biến những khoảnh khắc hài lòng ngắn ngủi trên ghế nha thành một **Mối quan hệ trọn đời (LTV Max)** có chủ đích.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1d186a84-d5b4-4afb-b080-fffc2057e5a3','4f9b559c-980e-4c99-a77d-e8b1883468aa',138,'text','**Bản đồ giá trị của tầng cộng đồng bệnh nhân**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('6434e6de-a200-47cf-bc8d-8ec42f78c875','4f9b559c-980e-4c99-a77d-e8b1883468aa',139,'text','Khi một phòng khám vận hành trơn tru cấu phần này, bộ máy kinh doanh sẽ tự động sản sinh ra 5 dòng giá trị kinh tế trực tiếp:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2d0ac4a2-7134-4bb4-bbdb-9e0553b4a18f','4f9b559c-980e-4c99-a77d-e8b1883468aa',140,'text','- **Quay lại (Repeat Visit):** Khách hàng cũ chủ động sử dụng thêm các dịch vụ phát sinh (Cross-sell/Up-sell) khi có nhu cầu điều trị mới.- **Tái khám (Recall Rate):** Lấp đầy công suất ghế nha vào các ngày trong tuần nhờ đường ống nhắc lịch tự động chạy ngầm trên CRM theo đúng chu kỳ sinh học.- **Hội viên (Membership):** Chuyển đổi dòng tiền thu sau thành dòng tiền trả trước thông qua các gói thẻ gia đình và đặc quyền đặc lợi phi y khoa.- **Giới thiệu (Referral System):** Kích hoạt ngọn lửa truyền miệng tự nhiên, biến mỗi thành viên cộng đồng thành một chiến binh lan tỏa lead nóng chất lượng cao với chi phí CAC bằng 0.- **Doanh thu hữu cơ (Sustainable Revenue):** Tạo ra một màng lọc bảo vệ doanh nghiệp trước các cơn bão quét thuật toán hay sự bão hòa của thị trường quảng cáo Paid Ads.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48688c06-af06-49e0-9484-d0fb11aba4d3','4f9b559c-980e-4c99-a77d-e8b1883468aa',141,'text','**Mantra cốt lõi của Dental Empire OS:** Bệnh nhân không mua vật liệu sứ hay trụ implant, họ mua sự an tâm trọn đời. Khi bác sĩ điều trị bằng sự tử tế, bệnh nhân sẽ tự động trở thành những chiến binh bảo vệ thương hiệu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9bd941d2-cb51-4e88-9674-cc5f1e0461c5','4f9b559c-980e-4c99-a77d-e8b1883468aa',142,'image',NULL,'book/18-patient-community/94c2e68a-155e-4ed4-b6a1-67e55ce89759-img08.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('12e58711-cd69-47c0-9e76-838060ddf052','4f9b559c-980e-4c99-a77d-e8b1883468aa',143,'text','Hệ sinh thái **Patient Community** chính là mảnh ghép cuối cùng hoàn thiện trục dọc trải nghiệm. Một khi pháo đài này được xây dựng vững chắc, phòng khám của bạn không chỉ sở hữu một thương hiệu nha khoa uy tín trên mặt đất, mà còn làm chủ một tài sản hệ thống vô giá, sẵn sàng tăng trưởng bùng nổ và trường tồn trước mọi biến động của thị trường.',NULL,NULL,NULL,NULL,NULL);
